import { createServerClient } from '@supabase/ssr'
import { createClient } from '@supabase/supabase-js'
import content from '@/content/es.json'

const c = content as any
const supabaseUrl = c.supabase.url
const supabaseAnonKey = c.supabase.anonKey

// SSR client for cookie-based auth
function getSSRClient(req: NextRequest) {
  return createServerClient(supabaseUrl, supabaseAnonKey, {
    cookies: {
      getAll() { return req.cookies.getAll() },
      setAll() {},
    },
  })
}

// Cached service-role client for admin ops
let _svc: ReturnType<typeof createClient> | null = null
function getServiceClient() {
  if (!_svc) {
    _svc = createClient(supabaseUrl, supabaseAnonKey, {
      auth: { persistSession: false },
      global: { headers: { apikey: supabaseAnonKey, Authorization: `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}` } },
    })
  }
  return _svc
}

export async function POST(req: NextRequest) {
  try {
    const authHeader = req.headers.get('authorization') || ''
    const bearerToken = authHeader.startsWith('Bearer ') ? authHeader.slice(7) : ''
    const body = await req.json()
    const { action } = body

    if (action === 'me') {
      let user: any = null

      // 1) Try cookie-based auth
      const ssr = getSSRClient(req)
      const { data: { session } } = await ssr.auth.getSession()
      if (session?.user) user = session.user

      // 2) Fallback to token-based auth — pass explicit JWT to getUser()
      if (!user && bearerToken) {
        const svc = getServiceClient()
        const { data, error } = await svc.auth.getUser(bearerToken)
        if (data?.user) {
          user = data.user
        } else {
          console.error('Token auth error:', error?.message)
        }
      }

      if (!user) {
        return NextResponse.json({ ok: false, error: 'No hay sesión' }, { status: 401 })
      }

      // Use service role to read profile (bypasses RLS)
      const svc = getServiceClient()
      const { data: profileRow } = await svc.from('profiles').select('*').eq('id', user.id).single()
      const profile = profileRow as Record<string, any> | null

      return NextResponse.json({
        ok: true,
        user: {
          id: user.id,
          name: profile?.name || user.email?.split('@')[0] || '',
          email: user.email,
          phone: profile?.phone || '',
          role: profile?.role || 'customer',
          createdAt: profile?.created_at || user.created_at,
        },
      })
    }

    if (action === 'login') {
      const supabase = getSSRClient(req)
      const { email, password } = body
      const { data, error } = await supabase.auth.signInWithPassword({ email, password })
      if (error) return NextResponse.json({ ok: false, error: 'Credenciales incorrectas' }, { status: 401 })
      return NextResponse.json({
        ok: true,
        session: {
          access_token: data.session?.access_token,
          refresh_token: data.session?.refresh_token,
        }
      })
    }

    if (action === 'register') {
      const supabase = getSSRClient(req)
      const { name, email, password, phone } = body
      const { error } = await supabase.auth.signUp({
        email, password,
        options: { data: { name, phone }, emailRedirectTo: `https://el-viajero.paragu-ai.com/auth/callback` }
      })
      if (error) {
        if (error.message.includes('already registered')) return NextResponse.json({ ok: false, error: 'Email ya registrado' }, { status: 409 })
        return NextResponse.json({ ok: false, error: error.message }, { status: 400 })
      }
      return NextResponse.json({ ok: true })
    }

    if (action === 'logout') {
      const supabase = getSSRClient(req)
      await supabase.auth.signOut()
      return NextResponse.json({ ok: true })
    }

    return NextResponse.json({ error: 'Acción desconocida' }, { status: 400 })
  } catch (err) {
    return NextResponse.json({ error: String(err) }, { status: 500 })
  }
}
